starterCss:
/* Style each card with the described border type.
   All cards should have 2px borders and 16px padding.
   The rounded card should have a 8px border-radius. */
.card {
  margin: 8px;
  padding: 16px;
}

referenceSolutions:
.card {
  margin: 8px;
  padding: 16px;
}
.solid {
  border: 2px solid rgb(0, 0, 0);
}
.dashed {
  border: 2px dashed rgb(0, 0, 0);
}
.dotted {
  border: 2px dotted rgb(0, 0, 0);
}
.rounded {
  border: 2px solid rgb(0, 0, 0);
  border-radius: 8px;
}

.card {
  margin: 8px;
  padding: 16px;
  border-width: 2px;
  border-color: black;
}
.solid {
  border-style: solid;
}
.dashed {
  border-style: dashed;
}
.dotted {
  border-style: dotted;
}
.rounded {
  border-style: solid;
  border-radius: 8px;
}

